/* Browser bundle — generated by scripts/build-bundle.js
 * DO NOT EDIT BY HAND. Edit lib/*.core.js and run: node scripts/build-bundle.js
 * Prefixed 00_ so tweego includes it before wrappers (alphabetical order).
 */

(function () {
    "use strict";

    // ---- _PRNGCore ----

    /** MurmurHash3 finalizer — hashes a string to a uint32. */
    function hash(str) {
        let h = 0xdeadbeef;
        for (let i = 0; i < str.length; i++) {
            h = Math.imul(h ^ str.charCodeAt(i), 0x9e3779b9);
        }
        h ^= h >>> 16;
        h = Math.imul(h, 0x85ebca6b);
        h ^= h >>> 13;
        h = Math.imul(h, 0xc2b2ae35);
        h ^= h >>> 16;
        return h >>> 0;
    }

    /** Create a xoshiro128** PRNG from four uint32 state values. */
    function makeXoshiro128ss(a, b, c, d) {
        let s0 = a, s1 = b, s2 = c, s3 = d;
        return {
            next() {
                const t = s1 << 9;
                let r = s0 * 5;
                r = ((r << 7) | (r >>> 25)) * 9;
                s2 ^= s0; s3 ^= s1; s1 ^= s2; s0 ^= s3;
                s2 ^= t;
                s3 = (s3 << 11) | (s3 >>> 21);
                return (r >>> 0) / 0x100000000;
            },
            nextInt(n) {
                return Math.floor(this.next() * n);
            },
            fork(key) {
                const s = hash(key + String(this.nextInt(0xffffffff)));
                return makeXoshiro128ss(
                    hash("a" + s), hash("b" + s),
                    hash("c" + s), hash("d" + s)
                );
            }
        };
    }

    /** Seed a PRNG from a string. */
    function seedFromString(str) {
        return makeXoshiro128ss(
            hash(str + "a"), hash(str + "b"),
            hash(str + "c"), hash(str + "d")
        );
    }

    window._PRNGCore = { hash, makeXoshiro128ss, seedFromString };

    // ---- _LibraryCore ----

    const BOTTOM_FLOOR = 0;
    const BOOKS_PER_GALLERY   = 192;  // 24 wide × 8 tall — one shelf face
    const GALLERIES_PER_SEGMENT = 10; // gallery pages between rest areas
    const SEGMENT_BOOK_COUNT  = BOOKS_PER_GALLERY * GALLERIES_PER_SEGMENT; // 1920

    /** True when a position falls on a rest area (kiosk, beds, stairs). */
    function isRestArea(position) {
        return position % GALLERIES_PER_SEGMENT === 0;
    }

    const DIRS = {
        LEFT:  "left",
        RIGHT: "right",
        UP:    "up",
        DOWN:  "down",
        CROSS: "cross",
    };

    /** Canonical string key for a location. */
    function locationKey({ side, position, floor }) {
        return `${side}:${position}:${floor}`;
    }

    /**
     * Generate a segment deterministically from its coordinates.
     *
     * @param {number} side
     * @param {number} position
     * @param {number} floor
     * @param {function} forkRng - (key: string) => rng instance
     * @returns {object} segment descriptor
     */
    function generateSegment(side, position, floor, forkRng) {
        const rng = forkRng("seg:" + locationKey({ side, position, floor }));

        const lightLevel = rng.next() < 0.05 ? "dim" : "normal";

        // Rest area only at gallery boundaries (position % GALLERIES_PER_SEGMENT === 0)
        const atRestArea = isRestArea(position);
        const restArea = atRestArea ? {
            hasStairs: true,
            hasKiosk: true,
            bedsAvailable: 7,
            hasZoroastrianText: position === 0,
        } : null;

        // Bridge only at floor 0 rest areas
        const hasBridge = floor === BOTTOM_FLOOR && atRestArea;

        return {
            side,
            position,
            floor,
            lightLevel,
            restArea,
            hasBridge,
            bookCount: BOOKS_PER_GALLERY,
        };
    }

    /** Returns available moves from a given location. */
    function availableMoves({ side, position, floor }) {
        const moves = [];

        moves.push(DIRS.LEFT);
        moves.push(DIRS.RIGHT);

        // stairs/bridge only accessible from rest areas
        if (isRestArea(position)) {
            if (floor > BOTTOM_FLOOR) moves.push(DIRS.DOWN);
            moves.push(DIRS.UP);
            if (floor === BOTTOM_FLOOR) moves.push(DIRS.CROSS);
        }

        return moves;
    }

    /** Apply a move to a location, returning new coordinates. */
    function applyMove({ side, position, floor }, dir) {
        switch (dir) {
            case DIRS.LEFT:  return { side, position: position - 1, floor };
            case DIRS.RIGHT: return { side, position: position + 1, floor };
            case DIRS.UP:
                if (!isRestArea(position)) throw new Error("Stairs only accessible from rest areas");
                return { side, position, floor: floor + 1 };
            case DIRS.DOWN:
                if (floor <= BOTTOM_FLOOR) throw new Error("Cannot descend below floor 0");
                if (!isRestArea(position)) throw new Error("Stairs only accessible from rest areas");
                return { side, position, floor: floor - 1 };
            case DIRS.CROSS:
                if (floor !== BOTTOM_FLOOR) throw new Error("Can only cross at the bottom floor");
                if (!isRestArea(position)) throw new Error("Bridge only accessible from rest areas");
                return { side: side === 0 ? 1 : 0, position, floor };
            default:
                throw new Error(`Unknown direction: ${dir}`);
        }
    }

    /** Human-readable description of a location. */
    function describeLocation({ side, position, floor }) {
        const sideLabel = side === 0 ? "west" : "east";
        return `${sideLabel} corridor, segment ${position}, floor ${floor}`;
    }

    window._LibraryCore = { DIRS, BOTTOM_FLOOR, SEGMENT_BOOK_COUNT, BOOKS_PER_GALLERY, GALLERIES_PER_SEGMENT, isRestArea, locationKey, generateSegment, availableMoves, applyMove, describeLocation };

    // ---- _BookCore ----

    const PAGES_PER_BOOK  = 410;
    const LINES_PER_PAGE  = 40;
    const CHARS_PER_LINE  = 80;
    const CHARS_PER_PAGE  = LINES_PER_PAGE * CHARS_PER_LINE; // 3200
    const CHARS_PER_BOOK  = PAGES_PER_BOOK * CHARS_PER_PAGE; // 1,312,000

    /**
     * The 95-character printable ASCII set (codepoints 32–126).
     * This matches what the book describes as "about 95 possible characters
     * on a standard keyboard."
     */
    const CHARSET = Array.from({ length: 95 }, (_, i) => String.fromCharCode(i + 32)).join("");

    /**
     * Generate a single page of a book as a string of CHARS_PER_PAGE characters.
     * Lines are separated by '\n' so the result is 40 lines of 80 chars each.
     *
     * @param {number} side
     * @param {number} position
     * @param {number} floor
     * @param {number} bookIndex  - 0-based index within the segment
     * @param {number} pageIndex   - 0-based page number (0–409)
     * @param {string} globalSeed  - the game's root seed string
     * @returns {string}
     */
    function generateBookPage(side, position, floor, bookIndex, pageIndex, globalSeed) {
        const rng = seedFromString(`${globalSeed}:book:${side}:${position}:${floor}:${bookIndex}:p${pageIndex}`);
        const n = CHARSET.length;
        const lines = [];
        for (let l = 0; l < LINES_PER_PAGE; l++) {
            let line = "";
            for (let c = 0; c < CHARS_PER_LINE; c++) {
                line += CHARSET[rng.nextInt(n)];
            }
            lines.push(line);
        }
        return lines.join("\n");
    }

    /**
     * Generate metadata for a book (deterministic, cheap — no character generation).
     * The spine/cover looks identical for all books; this supplies the index for
     * display and future proximity-signal logic.
     *
     * @param {number} side
     * @param {number} position
     * @param {number} floor
     * @param {number} bookIndex
     * @returns {{ side, position, floor, bookIndex }}
     */
    function bookMeta(side, position, floor, bookIndex) {
        return { side, position, floor, bookIndex };
    }

    /**
     * Scan a page for the longest coherent-looking run: sequences of printable
     * words separated by spaces (heuristic: only [a-zA-Z ,.'!?-] for 4+ chars).
     * Returns null if nothing meaningful found.
     *
     * Used by the proximity-signal system to surface fragments near the player's book.
     *
     * @param {string} pageText
     * @returns {string|null}
     */
    function findCoherentFragment(pageText) {
        const match = pageText.match(/[a-zA-Z ,.'!?\-]{4,}/g);
        if (!match) return null;
        // Return longest match
        return match.reduce((best, s) => s.length > best.length ? s : best, "");
    }

    window._BookCore = { PAGES_PER_BOOK, LINES_PER_PAGE, CHARS_PER_LINE, CHARS_PER_PAGE, CHARS_PER_BOOK, CHARSET, generateBookPage, bookMeta, findCoherentFragment };

    // ---- _LifeStoryCore ----

    // Template pools
    const FIRST_NAMES = [
        "Alma","Cedric","Dolores","Edmund","Fatima","Gordon","Helena","Ivan",
        "Judith","Kaspar","Leonora","Marcus","Nadia","Oliver","Priya","Quentin",
        "Rosa","Sebastian","Thea","Ulrich","Vera","Walter","Xenia","Yusuf","Zara",
    ];

    const LAST_NAMES = [
        "Ashby","Brant","Crane","Dahl","Ellison","Ferris","Gould","Harlow",
        "Ingram","Janssen","Keane","Lund","Marsh","Noel","Okafor","Pratt",
        "Quinn","Rowe","Strand","Thorn","Ueda","Voss","Ward","Xiao","Yuen",
    ];

    const OCCUPATIONS = [
        "librarian","schoolteacher","electrician","bus driver","accountant",
        "nurse","carpenter","postal worker","journalist","farmer",
        "chemist","translator","architect","cook","taxi driver",
        "dentist","watchmaker","bookbinder","radio operator","cartographer",
    ];

    const HOMETOWNS = [
        "a small town on the coast","a city you mostly tried to leave",
        "a suburb that no longer exists","a valley that flooded years later",
        "a neighborhood that changed while you were away",
        "a village your parents never stopped talking about",
        "a town whose name you could never spell correctly",
        "somewhere flat, with good light in the mornings",
    ];

    const CAUSE_OF_DEATH = [
        "a stroke, in the night, without warning",
        "a car accident on a road you'd driven a hundred times",
        "a long illness you pretended wasn't serious",
        "a fall — stupid, domestic, final",
        "a heart that simply stopped, as hearts do",
        "cancer, which took its time",
        "pneumonia, in a winter that was otherwise mild",
        "an accident at work that shouldn't have been possible",
    ];

    const LAST_THINGS = [
        "You were thinking about what to have for dinner.",
        "You had meant to call someone back.",
        "You were in the middle of a sentence.",
        "You had just put on a pot of coffee.",
        "You were looking out a window.",
        "You were tired, but not unusually so.",
        "You had a book open on the table.",
        "You were making a list.",
    ];

    const FLOORS_TOTAL = 1000; // effectively unbounded; use large number for coord gen

    /**
     * Generate a life story and book coordinates from a seed string.
     *
     * @param {string} seed
     * @returns {{
     *   name: string,
     *   occupation: string,
     *   hometown: string,
     *   causeOfDeath: string,
     *   lastThing: string,
     *   bookCoords: { side: number, position: number, floor: number, bookIndex: number }
     * }}
     */
    function generateLifeStory(seed) {
        const rng = seedFromString("life:" + seed);
        const pick = (arr) => arr[rng.nextInt(arr.length)];

        const firstName = pick(FIRST_NAMES);
        const lastName  = pick(LAST_NAMES);

        // Book coordinates: derived independently so changing template pools
        // doesn't shift everyone's book.
        const coordRng  = seedFromString("coords:" + seed);
        const side      = coordRng.nextInt(2);
        // Position: spread across a wide range so players rarely start near their book
        const position  = coordRng.nextInt(10000) - 5000;
        const floor     = coordRng.nextInt(100);
        const bookIndex = coordRng.nextInt(SEGMENT_BOOK_COUNT);

        return {
            name:         `${firstName} ${lastName}`,
            occupation:   pick(OCCUPATIONS),
            hometown:     pick(HOMETOWNS),
            causeOfDeath: pick(CAUSE_OF_DEATH),
            lastThing:    pick(LAST_THINGS),
            bookCoords:   { side, position, floor, bookIndex },
        };
    }

    /**
     * Format a life story as a short prose paragraph.
     *
     * @param {ReturnType<typeof generateLifeStory>} story
     * @returns {string}
     */
    function formatLifeStory(story) {
        return [
            `Your name was ${story.name}.`,
            `You were a ${story.occupation}, from ${story.hometown}.`,
            `You died of ${story.causeOfDeath}.`,
            story.lastThing,
            ``,
            `Somewhere in this library is a book that contains every detail of your life — `,
            `every word you ever spoke, every thought you kept to yourself, every morning `,
            `you woke up and made coffee or didn't. Find it. Submit it. Go home.`,
        ].join(" ");
    }

    window._LifeStoryCore = { generateLifeStory, formatLifeStory };

    // ---- _SurvivalCore ----

    const STAT_MAX = 100;
    const STAT_MIN = 0;

    /** Default starting state. */
    function defaultStats() {
        return {
            hunger:     80,
            thirst:     80,
            exhaustion: 90,
            morale:     100,
            despairing: false,
        };
    }

    /**
     * Clamp a value between STAT_MIN and STAT_MAX.
     * @param {number} v
     * @returns {number}
     */
    function clamp(v) {
        return Math.max(STAT_MIN, Math.min(STAT_MAX, v));
    }

    /**
     * Apply depletion for a move or wait action.
     * Returns a new stats object (does not mutate).
     *
     * @param {object} stats
     * @returns {object}
     */
    function applyMove(stats) {
        let { hunger, thirst, exhaustion, morale, despairing } = stats;

        hunger     = clamp(hunger     - 0.5);
        thirst     = clamp(thirst     - 2);
        exhaustion = clamp(exhaustion - 1);

        // Morale penalties for zeroed stats
        if (hunger     <= STAT_MIN) morale = clamp(morale - 2);
        if (thirst     <= STAT_MIN) morale = clamp(morale - 4);
        if (exhaustion <= STAT_MIN) morale = clamp(morale - 1);

        if (morale <= STAT_MIN) despairing = true;

        return { hunger, thirst, exhaustion, morale, despairing };
    }

    /**
     * Apply effects of sleeping (one full rest).
     * Exhaustion restored, hunger ticks down (time passes), thirst ticks down.
     *
     * @param {object} stats
     * @returns {object}
     */
    function applySleep(stats) {
        let { hunger, thirst, exhaustion, morale, despairing } = stats;

        exhaustion = STAT_MAX;
        hunger     = clamp(hunger - 10);
        thirst     = clamp(thirst - 8);

        // Small morale boost from rest
        morale = clamp(morale + 5);
        if (morale > STAT_MIN) despairing = false;

        return { hunger, thirst, exhaustion, morale, despairing };
    }

    /**
     * Apply eating (consuming one food item from kiosk).
     *
     * @param {object} stats
     * @returns {object}
     */
    function applyEat(stats) {
        return { ...stats, hunger: clamp(stats.hunger + 40) };
    }

    /**
     * Apply drinking (consuming one drink item from kiosk).
     *
     * @param {object} stats
     * @returns {object}
     */
    function applyDrink(stats) {
        return { ...stats, thirst: clamp(stats.thirst + 40) };
    }

    /**
     * Get a severity label for a stat value.
     * Used for UI warnings.
     *
     * @param {number} value
     * @returns {"critical"|"low"|"ok"}
     */
    function severity(value) {
        if (value <= 10) return "critical";
        if (value <= 30) return "low";
        return "ok";
    }

    /**
     * Get all active warning messages for a stats object.
     * Returns array of strings (empty if all ok).
     *
     * @param {object} stats
     * @returns {string[]}
     */
    function getWarnings(stats) {
        const w = [];
        if (severity(stats.thirst)     === "critical") w.push("You are desperately thirsty.");
        else if (severity(stats.thirst) === "low")     w.push("You are thirsty.");
        if (severity(stats.hunger)     === "critical") w.push("You are desperately hungry.");
        else if (severity(stats.hunger) === "low")     w.push("You are hungry.");
        if (severity(stats.exhaustion) === "critical") w.push("You can barely keep your eyes open.");
        else if (severity(stats.exhaustion) === "low") w.push("You are exhausted.");
        if (stats.despairing)                          w.push("You have given up hope.");
        return w;
    }

    window._SurvivalCore = { STAT_MAX, STAT_MIN, defaultStats, applyMove, applySleep, applyEat, applyDrink, severity, getWarnings };
}());
